# Generated by GitHub Copilot
[CmdletBinding()]
param(
    [switch]$Json
)

# Generated by GitHub Copilot
function Get-PackageMap {
    param(
        [Parameter(Mandatory = $true)]
        [pscustomobject]$PackageJson
    )

    $merged = @{}
    foreach ($field in @("dependencies", "devDependencies", "peerDependencies")) {
        if ($PackageJson.PSObject.Properties.Name -contains $field -and $null -ne $PackageJson.$field) {
            foreach ($property in $PackageJson.$field.PSObject.Properties) {
                $merged[$property.Name] = $property.Value
            }
        }
    }

    return $merged
}

# Generated by GitHub Copilot
function New-Status {
    param(
        [Parameter(Mandatory = $true)]
        [bool]$Pass,
        [Parameter(Mandatory = $true)]
        [string]$Ok,
        [Parameter(Mandatory = $true)]
        [string]$Fail,
        [switch]$NotApplicable
    )

    if ($NotApplicable) {
        return [ordered]@{
            pass = $true
            state = "N/A"
            detail = "not applicable"
        }
    }

    return [ordered]@{
        pass = $Pass
        state = if ($Pass) { "PASS" } else { "FAIL" }
        detail = if ($Pass) { $Ok } else { $Fail }
    }
}

# Generated by GitHub Copilot
function Test-Phase1ContractCase {
    param(
        [Parameter(Mandatory = $true)]
        [string]$RepoPath,
        [Parameter(Mandatory = $true)]
        [string]$Selector,
        [Parameter(Mandatory = $true)]
        [string]$SuccessDetail,
        [Parameter(Mandatory = $true)]
        [string]$FailureDetail
    )

    $testFile = Join-Path $RepoPath "backend/tests/test_api.py"
    if (-not (Test-Path -Path $testFile -PathType Leaf)) {
        return New-Status -Pass $false -Ok $SuccessDetail -Fail "missing backend/tests/test_api.py"
    }

    if (-not (Get-Command python -ErrorAction SilentlyContinue)) {
        return New-Status -Pass $false -Ok $SuccessDetail -Fail "python executable not found"
    }

    $backendPath = Join-Path $RepoPath "backend"
    Push-Location $backendPath
    try {
        python -m pytest tests/test_api.py -k $Selector -q *> $null
        $passed = $LASTEXITCODE -eq 0
    }
    finally {
        Pop-Location
    }

    return New-Status -Pass $passed -Ok $SuccessDetail -Fail $FailureDetail
}

$repoRoot = Split-Path -Parent (Split-Path -Parent $MyInvocation.MyCommand.Path)
$repoName = Split-Path -Leaf $repoRoot
$isUiLibrary = $repoName -eq "agentic-ui"

$backendMain = Join-Path $repoRoot "backend/app/main.py"
$backendMiddleware = Join-Path $repoRoot "backend/app/middleware.py"
$backendTests = Join-Path $repoRoot "backend/tests"
$frontendPackage = Join-Path $repoRoot "frontend/package.json"
$rootPackage = Join-Path $repoRoot "package.json"

$backendEntry = if ($isUiLibrary) {
    New-Status -Pass $true -Ok "ui library" -Fail "ui library" -NotApplicable
} else {
    New-Status -Pass (Test-Path -Path $backendMain -PathType Leaf) -Ok "backend entry found" -Fail "missing backend/app/main.py"
}

if ($isUiLibrary) {
    $requestId = New-Status -Pass $true -Ok "ui library" -Fail "ui library" -NotApplicable
    $securityHeaders = New-Status -Pass $true -Ok "ui library" -Fail "ui library" -NotApplicable
    $probes = New-Status -Pass $true -Ok "ui library" -Fail "ui library" -NotApplicable
    $probeAliases = New-Status -Pass $true -Ok "ui library" -Fail "ui library" -NotApplicable
    $backendTestsStatus = New-Status -Pass $true -Ok "ui library" -Fail "ui library" -NotApplicable
    $phase1Auth = New-Status -Pass $true -Ok "ui library" -Fail "ui library" -NotApplicable
    $phase1Error = New-Status -Pass $true -Ok "ui library" -Fail "ui library" -NotApplicable
} else {
    $backendContent = Get-Content -Path $backendMain -Raw -ErrorAction SilentlyContinue
    $middlewareContent = if (Test-Path -Path $backendMiddleware -PathType Leaf) { Get-Content -Path $backendMiddleware -Raw } else { "" }

    $requestId = New-Status -Pass (($backendContent -match 'X-Request-ID') -or ($middlewareContent -match 'X-Request-ID')) -Ok "request id propagation found" -Fail "missing request id propagation"
    $securityHeaders = New-Status -Pass (($backendContent -match 'Content-Security-Policy|SecurityHeadersMiddleware|apply_security_headers|X-Frame-Options') -or ($middlewareContent -match 'Content-Security-Policy|SecurityHeadersMiddleware|apply_security_headers|X-Frame-Options')) -Ok "security header controls found" -Fail "missing security header controls"
    $probes = New-Status -Pass (($backendContent -match '/health"|/health''') -and ($backendContent -match '/ready"|/ready''')) -Ok "health and readiness probes found" -Fail "missing /health or /ready"
    $probeAliases = New-Status -Pass (($backendContent -match '/healthz"|/healthz''') -and ($backendContent -match '/readyz"|/readyz''')) -Ok "probe aliases found" -Fail "missing /healthz or /readyz"
    $backendTestsStatus = New-Status -Pass (Test-Path -Path $backendTests -PathType Container) -Ok "backend tests folder found" -Fail "missing backend tests folder"
    $phase1Auth = Test-Phase1ContractCase -RepoPath $repoRoot -Selector "phase1_auth_required_contract" -SuccessDetail "phase1 auth contract test passed" -FailureDetail "phase1 auth contract test failed"
    $phase1Error = Test-Phase1ContractCase -RepoPath $repoRoot -Selector "phase1_error_contract_response" -SuccessDetail "phase1 error contract test passed" -FailureDetail "phase1 error contract test failed"
}

$frontendA11yPass = $false
$frontendNote = ""
if (Test-Path -Path $frontendPackage -PathType Leaf) {
    $package = Get-Content -Path $frontendPackage -Raw | ConvertFrom-Json
    $deps = Get-PackageMap -PackageJson $package
    $frontendA11yPass = $deps.ContainsKey("eslint-plugin-jsx-a11y") -and $deps.ContainsKey("@testing-library/react")
    $frontendNote = if ($frontendA11yPass) { "a11y + testing library present" } else { "missing eslint-plugin-jsx-a11y or @testing-library/react" }
} elseif (Test-Path -Path $rootPackage -PathType Leaf) {
    $package = Get-Content -Path $rootPackage -Raw | ConvertFrom-Json
    $deps = Get-PackageMap -PackageJson $package
    $frontendA11yPass = $deps.ContainsKey("@storybook/addon-a11y") -and $deps.ContainsKey("@testing-library/react")
    $frontendNote = if ($frontendA11yPass) { "storybook a11y + testing library present" } else { "missing @storybook/addon-a11y or @testing-library/react" }
} else {
    $frontendNote = "frontend package.json not found"
}
$frontendA11y = New-Status -Pass $frontendA11yPass -Ok "frontend a11y baseline found" -Fail $frontendNote

$checks = @($backendEntry, $requestId, $securityHeaders, $probes, $probeAliases, $backendTestsStatus, $phase1Auth, $phase1Error, $frontendA11y)
$overallPass = ($checks | Where-Object { -not $_.pass }).Count -eq 0
$noteItems = @()
foreach ($item in $checks) {
    if (-not $item.pass -and $item.state -ne "N/A") {
        $noteItems += $item.detail
    }
}

$result = [pscustomobject]@{
    App = $repoName
    BackendEntry = $backendEntry.state
    RequestId = $requestId.state
    SecurityHeaders = $securityHeaders.state
    Probes = $probes.state
    ProbeAliases = $probeAliases.state
    BackendTests = $backendTestsStatus.state
    Phase1Auth = $phase1Auth.state
    Phase1Error = $phase1Error.state
    FrontendA11y = $frontendA11y.state
    Overall = if ($overallPass) { "PASS" } else { "FAIL" }
    Notes = if ($noteItems.Count -eq 0) { "all checks passed" } else { $noteItems -join "; " }
}

$result | Format-Table -AutoSize

if ($Json) {
    $jsonPath = Join-Path $repoRoot "phase0-production-gate-report.json"
    $result | ConvertTo-Json -Depth 5 | Set-Content -Path $jsonPath -Encoding UTF8
    Write-Host "Saved JSON report to $jsonPath"
}

if (-not $overallPass) {
    exit 1
}
